class Solution:
    def catMouseGame(self, graph):
        # Minimax with memoization as independent oracle
        from functools import lru_cache
        n = len(graph)
        MOUSE_WIN, CAT_WIN, DRAW = 1, 2, 0
        MAX_TURNS = 2 * n * n

        @lru_cache(maxsize=None)
        def dp(mouse, cat, turn, moves):
            if moves >= MAX_TURNS:
                return DRAW
            if mouse == 0:
                return MOUSE_WIN
            if cat == mouse:
                return CAT_WIN
            if turn == 0:  # mouse's turn
                result = CAT_WIN  # worst case
                for nxt in graph[mouse]:
                    res = dp(nxt, cat, 1, moves + 1)
                    if res == MOUSE_WIN:
                        return MOUSE_WIN
                    if res == DRAW:
                        result = DRAW
                return result
            else:  # cat's turn
                result = MOUSE_WIN  # worst case
                for nxt in graph[cat]:
                    if nxt == 0:
                        continue
                    res = dp(mouse, nxt, 0, moves + 1)
                    if res == CAT_WIN:
                        return CAT_WIN
                    if res == DRAW:
                        result = DRAW
                return result

        return dp(1, 2, 0, 0)

