class Solution:
    def catMouseGame(self, graph):
        from collections import deque
        n = len(graph)
        MOUSE_TURN, CAT_TURN = 0, 1
        DRAW, MOUSE_WIN, CAT_WIN = 0, 1, 2

        # color[mouse][cat][turn] = result
        color = [[[0]*2 for _ in range(n)] for _ in range(n)]
        # degree[mouse][cat][turn] = number of moves available
        degree = [[[0]*2 for _ in range(n)] for _ in range(n)]

        for m in range(n):
            for c in range(n):
                degree[m][c][MOUSE_TURN] = len(graph[m])
                degree[m][c][CAT_TURN] = len([x for x in graph[c] if x != 0])

        queue = deque()

        # Terminal states
        for i in range(n):
            for t in range(2):
                # Mouse at hole: mouse wins
                if i != 0:
                    color[0][i][t] = MOUSE_WIN
                    queue.append((0, i, t))
                # Cat catches mouse: cat wins (cat != 0)
                if i != 0:
                    color[i][i][t] = CAT_WIN
                    queue.append((i, i, t))

        def parents(m, c, t):
            if t == MOUSE_TURN:
                # Previous state: cat's turn, cat was at some pc with edge to c
                for pc in graph[c]:
                    if pc != 0:
                        yield m, pc, CAT_TURN
            else:
                # Previous state: mouse's turn, mouse was at some pm with edge to m
                for pm in graph[m]:
                    yield pm, c, MOUSE_TURN

        while queue:
            m, c, t = queue.popleft()
            result = color[m][c][t]
            for pm, pc, pt in parents(m, c, t):
                if color[pm][pc][pt] != DRAW:
                    continue
                # If parent is the winner's turn, mark win
                if (result == MOUSE_WIN and pt == MOUSE_TURN) or (result == CAT_WIN and pt == CAT_TURN):
                    color[pm][pc][pt] = result
                    queue.append((pm, pc, pt))
                else:
                    # Decrease degree
                    degree[pm][pc][pt] -= 1
                    if degree[pm][pc][pt] == 0:
                        # All moves lead to opponent winning
                        color[pm][pc][pt] = result
                        queue.append((pm, pc, pt))

        return color[1][2][MOUSE_TURN]

