var catMouseGame = function(graph) {
    const n = graph.length;
    const MOUSE_TURN = 0, CAT_TURN = 1;
    const DRAW = 0, MOUSE_WIN = 1, CAT_WIN = 2;

    const color = Array.from({length: n}, () =>
        Array.from({length: n}, () => [0, 0]));
    const degree = Array.from({length: n}, () =>
        Array.from({length: n}, () => [0, 0]));

    for (let m = 0; m < n; m++) {
        for (let c = 0; c < n; c++) {
            degree[m][c][MOUSE_TURN] = graph[m].length;
            degree[m][c][CAT_TURN] = graph[c].filter(x => x !== 0).length;
        }
    }

    const queue = [];
    for (let i = 0; i < n; i++) {
        for (let t = 0; t < 2; t++) {
            if (i !== 0) {
                color[0][i][t] = MOUSE_WIN;
                queue.push([0, i, t]);
                if (color[i][i][t] === DRAW) {
                    color[i][i][t] = CAT_WIN;
                    queue.push([i, i, t]);
                }
            }
        }
    }

    function* parents(m, c, t) {
        if (t === MOUSE_TURN) {
            for (const pc of graph[c]) {
                if (pc !== 0) yield [m, pc, CAT_TURN];
            }
        } else {
            for (const pm of graph[m]) {
                yield [pm, c, MOUSE_TURN];
            }
        }
    }

    let head = 0;
    while (head < queue.length) {
        const [m, c, t] = queue[head++];
        const result = color[m][c][t];
        for (const [pm, pc, pt] of parents(m, c, t)) {
            if (color[pm][pc][pt] !== DRAW) continue;
            if ((result === MOUSE_WIN && pt === MOUSE_TURN) ||
                (result === CAT_WIN && pt === CAT_TURN)) {
                color[pm][pc][pt] = result;
                queue.push([pm, pc, pt]);
            } else {
                degree[pm][pc][pt]--;
                if (degree[pm][pc][pt] === 0) {
                    color[pm][pc][pt] = result;
                    queue.push([pm, pc, pt]);
                }
            }
        }
    }

    return color[1][2][MOUSE_TURN];
};
